             <td align="left" class="content" style="text-align: center;" width="388">
              <a class="image-link" href="https://substackcdn.com/image/fetch/f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fddbf8cf2-e683-44da-8c10-4b61b3dd52ad_388x508.png" rel="" style="align-items: center; border: none; display: block; flex-direction: column; height: auto; margin: 0; padding: 0; position: relative; text-decoration: none; width: auto;" target="_blank">
